package x509

import (
	"encoding/hex"
	"testing"
)

var pkcs8RSAPrivateKeyHex = ``

// Generated using:
//
//	openssl ecparam -genkey -name secp521r1 | openssl pkcs8 -topk8 -nocrypt
var pkcs8ECPrivateKeyHex = ``

// MLDSA44 Seed only case
var pkcs8MLDSA44PrivateKeyHex = `3034020100300b0609608648016503040311042280209365561af24ab0fd014dbad4b82756623ed8783def0332c957e0c52be98bf918`

// MLDSA65 Expanded Key only case
var pkcs8MLDSA65PrivateKeyHex = ``

// MLDSA87 Both Expanded Key and Seed case
var pkcs8MLDSA87PrivateKeyHex = ``

func TestPKCS8(t *testing.T) {
	derBytes, _ := hex.DecodeString(pkcs8RSAPrivateKeyHex)
	if _, err := ParsePKCS8PrivateKey(derBytes); err != nil {
		t.Errorf("failed to decode PKCS8 with RSA private key: %s", err)
	}

	derBytes, _ = hex.DecodeString(pkcs8ECPrivateKeyHex)
	if _, err := ParsePKCS8PrivateKey(derBytes); err != nil {
		t.Errorf("failed to decode PKCS8 with EC private key: %s", err)
	}

	derBytes, _ = hex.DecodeString(pkcs8MLDSA44PrivateKeyHex)
	if _, err := ParsePKCS8PrivateKey(derBytes); err != nil {
		t.Errorf("failed to decode PKCS8 with MLDSA44 private key: %s", err)
	}

	derBytes, _ = hex.DecodeString(pkcs8MLDSA65PrivateKeyHex)
	if _, err := ParsePKCS8PrivateKey(derBytes); err != nil {
		t.Errorf("failed to decode PKCS8 with MLDSA65 private key: %s", err)
	}

	derBytes, _ = hex.DecodeString(pkcs8MLDSA87PrivateKeyHex)
	if _, err := ParsePKCS8PrivateKey(derBytes); err != nil {
		t.Errorf("failed to decode PKCS8 with MLDSA87 private key: %s", err)
	}
}
